// Filter applies the MemberWhereInput filter on the MemberQuery builder.
func (i *MemberWhereInput) Filter(q *MemberQuery) (*MemberQuery, error) {
	if i == nil {
		return q, nil
	}
	p, err := i.P()
	if err != nil {
		if err == ErrEmptyMemberWhereInput {
			return q, nil
		}
		return nil, err
	}
	return q.Where(p), nil
}

