// AddPredicates adds custom predicates to the where input to be used during the filtering phase.
func (i *ZoneWhereInput) AddPredicates(predicates ...predicate.Zone) {
	i.Predicates = append(i.Predicates, predicates...)
}

// Filter applies the ZoneWhereInput filter on the ZoneQuery builder.
func (i *ZoneWhereInput) Filter(q *ZoneQuery) (*ZoneQuery, error) {
	if i == nil {
		return q, nil
	}
	p, err := i.P()
	if err != nil {
		if err == ErrEmptyZoneWhereInput {
			return q, nil
		}
		return nil, err
	}
	return q.Where(p), nil
}

